function solve(s) {
    const N = s.length;

    // 1. Calculate total counts
    let C0_total = 0;
    let C1_total = 0;
    for (const char of s) {
        if (char === '0') C0_total++;
        else C1_total++;
    }

    // Helper function to find the maximum length L such that Bal(s[a..b]) = target_diff
    // Returns [max_length, C0_in_segment, C1_in_segment] or [0, 0, 0]
    const findMaxLengthAndCounts = (target_diff) => {
        // Map stores {balance: smallest_index_k_where_P_k=balance}
        // P_{-1} = 0, stored at index -1.
        const min_idx = new Map();
        min_idx.set(0, -1);

        let current_balance = 0;
        let max_L = 0;
        let best_L_counts = [0, 0, 0]; // [L, C0, C1]

        for (let k = 0; k < N; k++) {
            const val = s[k] === '0' ? 1 : -1;
            current_balance += val;

            // We seek P_{a-1} = P_k - target_diff
            const required_prev_balance = current_balance - target_diff;

            if (min_idx.has(required_prev_balance)) {
                const a_prev = min_idx.get(required_prev_balance);
                const L = k - a_prev;

                // Calculate C0 and C1 for this segment [a_prev + 1, k]
                // Total balance difference = target_diff.
                // C0 - C1 = target_diff
                // C0 + C1 = L

                // 2*C0 = L + target_diff
                // 2*C1 = L - target_diff

                // Since L and target_diff have the same parity (L = P_k - P_{a-1}),
                // L + target_diff and L - target_diff are guaranteed to be even.
                const C0 = (L + target_diff) / 2;
                const C1 = (L - target_diff) / 2;

                if (L > max_L) {
                    max_L = L;
                    best_L_counts = [L, C0, C1];
                }
            }

            // Store the current balance if it's the first time we see it
            if (!min_idx.has(current_balance)) {
                min_idx.set(current_balance, k);
            }
        }
        return best_L_counts;
    };

    // --- Case 1: No swap (Target difference = 0) ---
    const [L_case1, _, __] = findMaxLengthAndCounts(0);
    let L_max = L_case1;

    // --- Case 2: One swap enables balance ---
    let L_K2 = 0;

    // K = 2: Substring has C0 = C1 + 2. Needs swap 0->1 outside.
    const [L_potential_2, C0_S_2, C1_S_2] = findMaxLengthAndCounts(2);
    if (L_potential_2 > 0) {
        // Feasibility check: Need an external '1' to swap with an internal '0'.
        // Internal '0' exists since C0_S_2 > 0 (L>=2).
        // External '1' exists if C1_total > C1_S_2.
        if (C1_total > C1_S_2) {
            L_K2 = Math.max(L_K2, L_potential_2);
        }
    }

    // K = -2: Substring has C1 = C0 + 2. Needs swap 1->0 outside.
    const [L_potential_neg2, C0_S_neg2, C1_S_neg2] = findMaxLengthAndCounts(-2);
    if (L_potential_neg2 > 0) {
        // Feasibility check: Need an external '0' to swap with an internal '1'.
        // Internal '1' exists since C1_S_neg2 > 0 (L>=2).
        // External '0' exists if C0_total > C0_S_neg2.
        if (C0_total > C0_S_neg2) {
            L_K2 = Math.max(L_K2, L_potential_neg2);
        }
    }

    return Math.max(L_case1, L_K2);
}

