def solve(s: String): Long = {
    // Helper function to find the maximum length L such that the balance P_k - P_{a-1} equals targetDiff
    // Returns (max_L, C0_in_segment, C1_in_segment)
    def findMaxLengthAndCounts(s: String, targetDiff: Int): (Int, Int, Int) = {
        val N = s.length
        // minIdx: balance -> smallest index k where P_k = balance
        // P_{-1} = 0, stored at index -1.
        var minIdx: Map[Int, Int] = Map(0 -> -1)
        var currentBalance = 0
        var maxL = 0
        var bestCounts = (0, 0, 0) // (L, C0, C1)

        for (k <- 0 until N) {
            // '0' maps to +1, '1' maps to -1
            val valK = if (s(k) == '0') 1 else -1
            currentBalance += valK

            // We seek P_{a-1} = P_k - target_diff
            val requiredPrevBalance = currentBalance - targetDiff

            if (minIdx.contains(requiredPrevBalance)) {
                val aPrev = minIdx(requiredPrevBalance)
                val L = k - aPrev // Length of segment [aPrev + 1, k]

                // Calculate C0 and C1
                // C0 - C1 = targetDiff
                // C0 + C1 = L

                // Since L and targetDiff must have the same parity for an integer solution,
                // and this is guaranteed by the prefix sum property when searching for a specific diff, we calculate directly.
                val C0 = (L + targetDiff) / 2
                val C1 = (L - targetDiff) / 2

                if (L > maxL) {
                    maxL = L
                    bestCounts = (L, C0, C1)
                }
            }

            // Store the current balance if it's the first time we see it (to maximize L = k - a_prev)
            if (!minIdx.contains(currentBalance)) {
                minIdx = minIdx + (currentBalance -> k)
            }
        }
        bestCounts
    }

    val N = s.length
    var c0Total = 0
    var c1Total = 0

    // 1. Calculate total counts
    for (char <- s) {
        if (char == '0') c0Total += 1
        else c1Total += 1
    }

    // --- Case 1: No swap (Target difference = 0) ---
    val (lCase1, _, _) = findMaxLengthAndCounts(s, 0)
    var lMax = lCase1

    // --- Case 2: One swap enables balance ---
    var lK2 = 0

    // Target D=2: Substring has C0 = C1 + 2. Needs one '0'->'1' flip inside/outside swap.
    val (lPotential2, c0S2, c1S2) = findMaxLengthAndCounts(s, 2)
    if (lPotential2 > 0) {
        // Feasibility check: Must have at least one '1' outside the segment to swap with an internal '0'.
        if (c1Total > c1S2) {
            lK2 = math.max(lK2, lPotential2)
        }
    }

    // Target D=-2: Substring has C1 = C0 + 2. Needs one '1'->'0' flip inside/outside swap.
    val (lPotentialNeg2, c0SNeg2, c1SNeg2) = findMaxLengthAndCounts(s, -2)
    if (lPotentialNeg2 > 0) {
        // Feasibility check: Must have at least one '0' outside the segment to swap with an internal '1'.
        if (c0Total > c0SNeg2) {
            lK2 = math.max(lK2, lPotentialNeg2)
        }
    }

    // The maximum length found is the result. Since L >= 0, casting to Long is safe.
    math.max(lCase1, lK2).toLong
}

