import scala.collection.mutable

object Solver {
    /**
     * Finds the maximum length L of a substring where C0 - C1 = targetDiff, 
     * and returns (L, C0, C1) for that segment.
     * C0: count of '0', C1: count of '1'.
     */
    private def findMaxLengthAndCounts(s: String, targetDiff: Int): (Int, Int, Int) = {
        val N = s.length

        // Map stores {balance: smallest_index_k_where_P_k=balance}
        // P_{-1} = 0, stored at index -1.
        val minIdx = mutable.Map[Int, Int]()
        minIdx.put(0, -1)

        var currentBalance = 0
        var maxL = 0
        // Store [L, C0, C1]
        var bestCounts = (0, 0, 0)

        for (k <- 0 until N) {
            // '0' -> +1, '1' -> -1
            val val_k = if (s(k) == '0') 1 else -1
            currentBalance += val_k

            // We seek P_{a-1} = P_k - targetDiff
            val requiredPrevBalance = currentBalance - targetDiff

            if (minIdx.contains(requiredPrevBalance)) {
                val a_prev = minIdx(requiredPrevBalance)
                val L = k - a_prev

                // Calculate C0 and C1 for this segment [a_prev + 1, k]
                // L = C0 + C1
                // targetDiff = C0 - C1
                // 2*C0 = L + targetDiff
                val C0 = (L + targetDiff) / 2
                // 2*C1 = L - targetDiff
                val C1 = (L - targetDiff) / 2

                if (L > maxL) {
                    maxL = L
                    bestCounts = (L, C0, C1)
                }
            }

            // Store the current balance if it's the first time we see it
            if (!minIdx.contains(currentBalance)) {
                minIdx.put(currentBalance, k)
            }
        }
        (maxL, bestCounts._2, bestCounts._3)
    }


    def s(s: String): Long = {
        val N = s.length

        // 1. Calculate total counts
        var c0Total = 0
        var c1Total = 0
        for (char <- s) {
            if (char == '0') c0Total += 1
            else c1Total += 1
        }

        // --- Case 1: No swap (Target difference = 0) ---
        val (L_case1, _, _) = findMaxLengthAndCounts(s, 0)
        var L_max = L_case1.toLong

        // --- Case 2: One swap enables balance ---

        // K = 2: Substring has C0 = C1 + 2. Needs external '1' to swap with internal '0'.
        val (L_potential_2, C0_S_2, C1_S_2) = findMaxLengthAndCounts(s, 2)
        if (L_potential_2 > 0) {
            // Feasibility check: Need an external '1' (C1_total > C1_S_2)
            if (c1Total > C1_S_2) {
                L_max = Math.max(L_max, L_potential_2.toLong)
            }
        }

        // K = -2: Substring has C1 = C0 + 2. Needs external '0' to swap with internal '1'.
        val (L_potential_neg2, C0_S_neg2, C1_S_neg2) = findMaxLengthAndCounts(s, -2)
        if (L_potential_neg2 > 0) {
            // Feasibility check: Need an external '0' (C0_total > C0_S_neg2)
            if (c0Total > C0_S_neg2) {
                L_max = Math.max(L_max, L_potential_neg2.toLong)
            }
        }

        L_max
    }
}
